var zk = {
    fancyboxHistory: [],
    fancyboxIndex: -1,
    formErrors: function(form, errors){
        for(i in errors){
            $(form).data('bootstrapValidator').updateStatus(i, 'INVALID');
            $('[data-bv-for="'+ i +'"]', $(form)).html(errors[i][0]);
        }
        return false;
    },
    confirm: function(message, callback, callbackCancel){
        $.prompt(message, {
            submit: function(e, v){
                e.preventDefault();
                if(v){
                    if(callback) callback();
                }else{
                    if(callbackCancel) callbackCancel();
                }

                $.prompt.close();
            },
            buttons: {
                'Si': true,
                'No': false
            }
        });
    },
    sendData: function(url, data, callback){
        _form = this;
        $.ajax({
            url: url,
            type: 'POST',
            beforeSend: function(){
                $('#page-content').niftyOverlay('show');
            },
            data: data,
            dataType: 'json',
            success: function(r){
                if(callback) return callback(r);
            },
            complete: function(){
               $('#page-content').niftyOverlay('hide');
            },
            error: function(){
                alert('No se pudo realizar la petición');
            }
        });
    },
    pageAlert: function(options){
        options = $.extend({
            type: 'info',
            message: '',
            title: '',
            time: 3000,
            icon: ''
        }, options);

        var html = '';
        if(options.icon != ''){
            html += '<div class="media-left">\
                <span class="icon-wrap icon-wrap-xs icon-circle alert-icon">\
                    <i class="fa fa-'+ options.icon +' fa-lg"></i>\
                </span>\
            </div>';
        }
        html += '<div class="media-body">';
        if(options.title != ''){
            html += '<h4 class="alert-title">'+ options.title +'</h4>';
        }
        html += '<p class="alert-message">'+ options.message +'</p>\
            </div>';

        $.niftyNoty({
            type: options.type,
            container : 'page',
            html : html,
            timer : options.time
        });
    }
};

function fancybox(url, addHistory){
    if(addHistory !== false){
        zk.fancyboxHistory.push(url);
        zk.fancyboxIndex = zk.fancyboxHistory.length - 1;
        //++zk.fancyboxIndex;
    }

    $.fancybox({
        href: url, 
        type: 'ajax', 
        enableEscapeButton: false,  
        hideOnOverlayClick: false, 
        overlayColor : '#FFF', 
        centerOnScroll: true, 
        scrolling: 'auto', 
        closeClick: false, 
        helpers: {
            overlay : {
                closeClick : false,
                background: '#fff'
            }
        }
    });
}

$.fn.extend({
    sendGateway: function(action){
        _form = this;
        _form.niftyOverlay('show');
        if(!action){
             action = this.attr('action');
             this.attr('action', '');
        }
        $('#ActionManager').remove();
        $('body').append('<iframe id="ActionManager" name="ActionManager" style="display: none"></iframe>');
        this.attr('method', 'POST');
        this.attr('target', 'ActionManager');
        this.attr('enctype','multipart/form-data');
        this.attr('action', action);
        form = document.getElementById(this.attr('id'));
        iframe = document.getElementById('ActionManager');
        form.submit();
    },
    sendForm: function(url, callback){
        _form = this;
        $.ajax({
            url: url,
            type: 'POST',
            beforeSend: function(){
                _form.niftyOverlay('show');
            },
            data: this.serialize(),
            dataType: 'json',
            success: function(r){
                if(callback) return callback(r);
            },
            complete: function(){
                _form.niftyOverlay('hide');
            },
            error: function(){
                alert('Request Failed!');
            }
        });
    },
    

});

$(window).on('keydown', function(e){
    if(e.keyCode == 119){
        zk.reloadPage();
    }
    if(e.keyCode == 120){
        $.fancybox.reload();
    }
    //console.log(e.keyCode);
})